package org.eclipse.rdf4j.http.server;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.util.zip.GZIPInputStream;

import org.eclipse.rdf4j.common.io.IOUtil;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class ServerHomeIT {

	private static TestServer server;

	@BeforeAll
	static void startServer() throws Exception {
		server = new TestServer();
		try {
			server.start();
		} catch (Exception e) {
			server.stop();
			throw e;
		}
	}

	@AfterAll
	static void stopServer() throws Exception {
		server.stop();
	}

	@Test
	public void homeOverviewViewReturnsReadableTitleForBrowsers() throws Exception {
		HttpURLConnection connection = (HttpURLConnection) new URL(TestServer.SERVER_URL + "/").openConnection();
		connection.setRequestProperty("Accept",
				"text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8");
		connection.setRequestProperty("Accept-Encoding", "gzip");

		assertThat(connection.getResponseCode()).isEqualTo(HttpURLConnection.HTTP_OK);
		assertThat(connection.getURL().toString()).endsWith("/home/overview.view");

		String body = readBody(connection);
		assertThat(body).contains("<title>RDF4J Server - Home</title>");
	}

	private static String readBody(HttpURLConnection connection) throws Exception {
		try (InputStream bodyStream = decode(connection.getInputStream(), connection.getContentEncoding())) {
			ByteArrayOutputStream body = new ByteArrayOutputStream();
			IOUtil.transfer(bodyStream, body);
			return body.toString(StandardCharsets.UTF_8);
		}
	}

	private static InputStream decode(InputStream inputStream, String contentEncoding) throws Exception {
		if ("gzip".equalsIgnoreCase(contentEncoding)) {
			return new GZIPInputStream(inputStream);
		}
		return inputStream;
	}
}
